package be.schaubroeck.lpb.rkm.rekenmotor.rsz.dmfa.bijdrage.patronaal;

import be.schaubroeck.lpb.rkm.rekenmotor.SleutelGegevens;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.MoneyKey;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenPatronaalPriveRszKey;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.dmfa.bijdrage.AbstractBijdrageMetPercentageBase;
import be.schaubroeck.lpb.rkm.rekenresultaat.service.util.RekenresultaatBedrag;
import be.schaubroeck.lpb.tools.enumtypes.DmfapplWnkengetal;
import be.schaubroeck.lpb.tools.service.RszConstantService;
import org.joda.time.LocalDate;

import java.math.BigDecimal;
import java.util.EnumSet;

/*
  Bedoeling is om voor elke bijdrage uiteindelijk een aparte class of zelfs package (als 1 class niet voldoende is) te krijgen.
  Zodat het minder complex wordt en het eenvoudig wordt om bijdrages toe te voegen / aan te passen / te verwijderen.
  1 factory die de bijdrage maakt (vervangt heleboel switches en/of if structures + keys)
  Elke bijdrage heeft dan
  * basis
  * percentage (Eventueel bepaald door een aparte class)
  * rekenresultaatbedrag
  * rekenbedragtype
  * ....
 */
public class WerkgelegenheidEnVorming extends AbstractBijdrageMetPercentageBase {
    public static final MoneyKey MONEY_KEY_INHOUDING = RekenPatronaalPriveRszKey.PATRONALE_BIJDRAGE_WERKGELEGENHEID_EN_VORMING_KEY;

    public static final RekenresultaatBedrag REKENRESULTAAT_BEDRAG_BASIS = RekenresultaatBedrag.BASIS_WERKGELEGENHEID_EN_VORMING;
    public static final RekenresultaatBedrag REKENRESULTAAT_BEDRAG_INHOUDING = RekenresultaatBedrag.PATRONALE_BIJDRAGE_WERKGELEGENHEID_EN_VORMING;

    private static final EnumSet<DmfapplWnkengetal> TOEGELATEN_KENGETALLEN = EnumSet.of(
            DmfapplWnkengetal.GEWONE_HANDARBEIDERS,
            DmfapplWnkengetal.GESUB_CONTRACTUELE_HANDARBEIDERS,
            DmfapplWnkengetal.LEERPLICHTIGE_GEWONE_HANDARBEIDERS,
            DmfapplWnkengetal.ANDERE_KUNSTENAARS,
            DmfapplWnkengetal.LEERPLICHTIGE_KUNSTENAARS,
            DmfapplWnkengetal.GESUB_CONTR_HOOFDARBEIDERS,
            DmfapplWnkengetal.LEERPLICHTIGE_HOOFDARBEIDERS,
            // 488
            DmfapplWnkengetal.GEWONE_HOOFDARBEIDERS);


    public WerkgelegenheidEnVorming(RszConstantService rszConstantService) {
        super(rszConstantService);
    }

    @Override
    public BigDecimal getPercentage(SleutelGegevens gegevens, LocalDate zoekDatum) {
        DmfapplWnkengetal werknemersKengetal = gegevens.getWerknemersKengetal();
        Integer typeLeerling = gegevens.getTypeLeerling();
        if (TOEGELATEN_KENGETALLEN.contains(werknemersKengetal) && typeLeerling != null && typeLeerling == 0) {
            return getWerkgeversPercentageZonderType(zoekDatum, gegevens.getWerkgeversCategorie(), DmfapplWnkengetal.WERKGELEGENHEID_EN_VORMING);
        }
        return BigDecimal.ZERO;
    }
}
